my $config_dir = shift @ARGV || './plugins';
my $plugin_registry = {};

sub load_plugin_config {
    my ($config_file) = @_;
    my $plugin_code = '';
    
    open my $fh, '<', $config_file or die "Cannot open config file $config_file: $!\n";
    while (my $line = <$fh>) {
        $plugin_code .= $line;
    }
    close $fh;
    
    return $plugin_code;
}

sub execute_plugin {
    my ($plugin_name, $plugin_code, @args) = @_;
    
    my $result;
    my $error;
    
    {
        local $@;
        $result = eval $plugin_code;
        $error = $@;
    }
    
    if ($error) {
        warn "Error executing plugin '$plugin_name': $error\n";
        return undef;
    }
    
    return $result;
}

sub register_plugin {
    my ($name, $code) = @_;
    $plugin_registry->{$name} = $code;
    print "Plugin '$name' registered successfully\n";
}

sub run_plugin {
    my ($name, @args) = @_;
    
    unless (exists $plugin_registry->{$name}) {
        warn "Plugin '$name' not found in registry\n";
        return undef;
    }
    
    my $plugin_code = $plugin_registry->{$name};
    return execute_plugin($name, $plugin_code, @args);
}

sub load_all_plugins {
    my ($dir) = @_;
    
    unless (-d $dir) {
        warn "Plugin directory '$dir' does not exist\n";
        return;
    }
    
    opendir my $dh, $dir or die "Cannot open directory $dir: $!\n";
    my @plugin_files = grep { /\.pl$/ && -f "$dir/$_" } readdir($dh);
    closedir $dh;
    
    foreach my $file (@plugin_files) {
        my $full_path = File::Spec->catfile($dir, $file);
        my $plugin_name = $file;
        $plugin_name =~ s/\.pl$//;
        
        print "Loading plugin: $plugin_name from $full_path\n";
        my $plugin_code = load_plugin_config($full_path);
        register_plugin($plugin_name, $plugin_code);
    }
}

